class Parser:
 def __init__(self, tokens):
 self.tokens = tokens
 self.lookahead = tokens[0]

 def parseX(self):
 # choose production for X based on lookahead
 if self.lookahead == 'terminal':
 self.match('terminal')
 elif self.lookahead == 'non-terminal':
 self.parseY()

 def match(self, expectedToken):
 if self.lookahead == expectedToken:
 self.consumeToken()
 else:
 raise SyntaxError('unexpected token')

 def consumeToken(self):
 self.tokens.pop(0)
 self.lookahead = self.tokens[0]

#include <stdio.h>
#include <stdlib.h>

// define parser structure
typedef struct Parser {
 char* tokens;
 char lookahead;
} Parser;

// initialize parser
Parser* initParser(char* tokens) {
 Parser* parser = malloc(sizeof(Parser));
 parser->tokens = tokens;
 parser->lookahead = tokens[0];
 return parser;
}

// parse function
void parseX(Parser* parser) {
 // choose production for X based on lookahead
 if (parser->lookahead == 'terminal') {
 match(parser, 'terminal');
 } else if (parser->lookahead == 'non-terminal') {
 parseY(parser);
 }
}

// match function
void match(Parser* parser, char expectedToken) {
 if (parser->lookahead == expectedToken) {
 consumeToken(parser);
 } else {
 printf('syntax error');
 exit(1);
 }
}

// consume token function
void consumeToken(Parser* parser) {
 parser->tokens++;
 parser->lookahead = parser->tokens[0];
}
